UPDATE article
SET like_count = CASE id

    WHEN #{item.articleId} THEN #{item.likeCount}

END
WHERE id IN

    #{item.articleId}

update article
set view_count = view_count + 1
where id = #{articleId}

update article
set comment_count = comment_count - 1
where id = #{articleId}

