select a.id, a.title, a.summary, a.cover_image as coverImage, a.type, a.published_at as updatedTime, a.view_count as viewCount, a.like_count as likeCount, a.comment_count as commentCount, a.collect_count as collectCount, a.share_count as shareCount, a.is_recommend as isRecommend, a.is_top as isTop,
u.id as userId, u.nickname as nickName, u.avatar as avatar, c.name as categoryName,
( ( a.view_count + a.like_count * 10 + a.comment_count * 5 + a.collect_count * 3 ) * 0.6 + (1 / (TIMESTAMPDIFF(HOUR, a.published_at, NOW()) + 2)) * 100 * 0.3 + (1 / (a.recommend_expose_count + 1)) * 50 * 0.1 ) as exploreScore
from article a left join user u on a.user_id = u.id left join category c on a.category_id = c.id
where a.visibility = 0 and a.status = 1 and a.published_at is not null
and a.id not in
#{id}
and a.id not in ( select atr.article_id from article_tag_relation atr where atr.tag_id in
#{tagId}
)
and a.view_count > 20
order by exploreScore desc
limit #{limit}

